  ('elementary-f29af906-moex-00318', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依原住民保留地開發管理辦法之規定，原住民申請無償取得原住民保留地所有權，若其為依法得供 建築使用之土地，土地面積最高限額為下列何者？', '["每戶1公頃", "每戶1.5公頃", "每戶0.1公頃", "每戶0.3公頃"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00319', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '同一標的之普通抵押權相關登記，下列敘述何者正確？', '["因次序讓與申請權利內容變更登記者，得由受讓人單獨申請登記", "因次序拋棄申請權利內容變更登記者，得由拋棄人單獨申請登記", "因次序讓與申請權利內容變更登記者，應由受讓人會同土地所有權人申請登記", "因次序拋棄申請權利內容變更登記者，應由拋棄人會同土地所有權人申請登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00320', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地法規定，地政機關所收登記費，應提存多少比例，作為登記錯誤等賠償之用？', '["百分之一", "百分之二", "百分之十", "百分之十五"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00321', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依國有財產法規定，非公用財產類不動產之出租，下列敘述何者錯誤？', '["得以標租方式辦理", "原有租賃期限屆滿，未逾6個月者，得逕予出租", "依法得讓售者，不得逕予出租", "應以書面為之；未以書面為之者，不生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00322', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依都市更新條例規定，有關權利變換計畫書之權利價值異議，下列敘述何者正確？', '["權利變換計畫書核定發布實施後 3 個月內，土地所有權人對其權利價值有異議時，應以書面敘明 理由，向各級主管機關提出", "各級主管機關應於受理異議後3個月內審議核復", "因情形特殊，經各級主管機關認有委託專業團體或機構協助作技術性諮商之必要者，得延長審議核 復期限2個月", "當事人對審議核復結果不服者，得依法提請民事救濟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00323', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依都市更新條例規定，權利變換範圍內，經權利變換分配之土地及建築物，實施者應以書面分別通知 受配人，限期辦理接管。下列何者為逾期不接管之處理方式？', '["自期限屆滿之日起，視為放棄", "自期限屆滿之翌日起，視為放棄", "自期限屆滿之翌日起，視為已接管", "自期限屆滿之日起，視為已接管"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00324', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依都市更新條例規定，下列何者不屬於應由直轄市、縣（市）主管機關視實際情況，迅行劃定或變更 更新地區之情形？', '["因戰爭、地震、火災、水災、風災或其他重大事變遭受損壞", "都市計畫範圍內非經目的事業主管機關指定具有歷史、文化、藝術及紀念價值且經結構安全性能評 估結果未達最低等級之建築物", "屋齡30年以上，經結構安全性能評估結果之建築物耐震能力未達一定標準，且改善不具效益或未 設置昇降設備之建築物", "為避免重大災害之發生"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00325', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地法規定，因登記錯誤、遺漏或虛偽致受損害者，由該地政機關負損害賠償責任；下列何種情形 應由該登記人員償還損害賠償，撥歸登記儲金？', '["登記人員無重大過失時", "登記人員有重大過失時", "登記人員有抽象輕過失時", "登記人員無過失時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00326', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例規定，有關一併徵收之敘述，下列何者正確？', '["應於徵收公告之日起2年內申請，逾期不受理", "補償費發給完竣前得以書面撤回申請", "應向內政部提出申請", "應向行政院提出申請"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00327', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例規定，下列有關徵收程序之敘述，何者正確？', '["需用土地人於事業計畫報請目的事業主管機關許可前，應舉行說明會", "特定農業區經行政院核定為重大建設須辦理徵收者，若有爭議，應依行政程序法舉行公聽會", "需用土地人申請徵收土地或土地改良物前，皆必須與所有權人協議價購，無一例外", "協議價購時，依其他法律規定有優先購買權者，無優先購買權之適用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
